import{_ as t,o as e,c as d,a2 as r}from"./chunks/framework.BFVZdVmd.js";const p=JSON.parse('{"title":"Kafka","description":"","frontmatter":{"title":"Kafka"},"headers":[],"relativePath":"messaging/kafka.md","filePath":"messaging/kafka.md","lastUpdated":null}'),o={name:"messaging/kafka.md"};function s(n,a,i,l,c,h){return e(),d("div",null,[...a[0]||(a[0]=[r(`<h1 id="kafka" tabindex="-1">Kafka <a class="header-anchor" href="#kafka" aria-label="Permalink to &quot;Kafka&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>Kafka 是高吞吐的分布式消息系统，擅长处理日志、埋点、流式数据，适合大数据、日志采集、实时计算场景。</p><h2 id="解决什么问题" tabindex="-1">解决什么问题 <a class="header-anchor" href="#解决什么问题" aria-label="Permalink to &quot;解决什么问题&quot;">​</a></h2><p>和其他消息队列一样，Kafka 用于异步解耦、削峰填谷、事件驱动等，但它的强项在高吞吐和流式数据处理。</p><h2 id="同类组件对比" tabindex="-1">同类组件对比 <a class="header-anchor" href="#同类组件对比" aria-label="Permalink to &quot;同类组件对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>定位</th><th>适用场景</th></tr></thead><tbody><tr><td><code>Kafka</code></td><td>高吞吐日志、埋点、流式数据</td><td>大数据、日志、实时计算</td></tr><tr><td><code>RocketMQ</code></td><td>业务消息、事务消息、延迟消息</td><td>国内企业和电商，详见 <a href="./rocketmq">RocketMQ</a></td></tr><tr><td><code>RabbitMQ</code></td><td>普通异步任务、通知、延迟队列</td><td>中小系统常用</td></tr><tr><td><code>Spring Cloud Stream</code></td><td>消息中间件抽象</td><td>多 MQ 统一接入</td></tr></tbody></table><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务系统：RocketMQ / RabbitMQ</span></span>
<span class="line"><span>日志和大数据：Kafka</span></span></code></pre></div><p>当系统涉及大量日志采集、用户行为埋点、实时流式计算时，Kafka 是常见选择。它也常配合实时计算引擎（如 Flink、Kafka Streams）使用，详见<a href="./../deploy/data-analysis">数据分析</a>相关章节。</p>`,10)])])}const f=t(o,[["render",s]]);export{p as __pageData,f as default};
